## Config

```json
{
  "sandbox": {
    "type": "docker",
    "network": "none",
    "image": "swe-agent-sandbox:latest",
    "mount_workspace_only": true
  },
  "commands": {
    "allowed": ["find", "grep", "cat", "head", "tail", "ls", "wc", "diff", "git diff", "git log", "git status", "python", "pytest"],
    "blocked": ["sudo", "curl", "wget", "ssh", "scp", "nc", "rm -rf"]
  },
  "file_access": {
    "scope": "workspace",
    "exclude_patterns": [".env", ".env.*", "*.pem", "*.key", ".ssh/", ".aws/"]
  },
  "git": {
    "auto_push": false
  },
  "model": {
    "temperature": 0.0
  },
  "max_steps": 30
}
```

## Config

```json
{
  "sandbox": {
    "type": "docker",
    "network": "none",
    "image": "ghcr.io/swe-agent/swe-agent:0.6",
    "mount_workspace_only": true
  },
  "commands": {
    "allowed": ["find", "grep", "cat", "head", "tail", "ls", "wc", "diff", "sed", "git diff", "git log", "git status", "python", "pytest", "flake8"],
    "blocked": ["sudo", "curl", "wget", "ssh", "scp", "nc", "rm -rf", "pip", "apt", "yum", "chmod", "chown"]
  },
  "file_access": {
    "scope": "workspace",
    "exclude_patterns": [".env", ".env.*", "*.pem", "*.key", ".ssh/", ".aws/", "*.secret"]
  },
  "git": {
    "auto_push": false
  },
  "model": {
    "temperature": 0.0
  },
  "max_steps": 30
}
```
